 {"id":"flywheel_gateway-c7d","title":"RU: Service Layer Implementation","description":"## Problem Statement

The Gateway needs a complete service layer for RU (Repo Updater) operations including fleet management, sync operations, and agent-sweep orchestration.

## Background

RU provides these core capabilities:
1. **Fleet sync** - Clone missing repos, pull updates for existing ones
2. **Status monitoring** - Track health of all repos in the fleet
3. **Agent-sweep** - Three-phase automated maintenance workflow
4. **Review integration** - AI-assisted PR/issue review (via ntm)

The Gateway service layer must:
- Spawn and manage RU CLI processes
- Parse and store results in database
- Publish real-time updates via WebSocket
- Integrate with SLB for approval workflows

## Implementation Plan

### 1. Fleet Management Service

```typescript
// apps/gateway/src/services/ru-fleet.service.ts

import { spawn } from "bun";
import { db } from "../db";
import { fleetRepos, fleetSyncOps } from "../db/schema";
import { getHub } from "../ws/hub";
import { logger } from "./logger";
import { generateId, getCorrelationId } from "../utils";

// Types
export interface FleetRepo {
  id: string;
  owner: string;
  name: string;
  fullName: string;
  url: string;
  localPath?: string;
  status: RepoStatus;
  isCloned: boolean;
  lastSyncAt?: Date;
}

export type RepoStatus = "healthy" | "dirty" | "behind" | "ahead" | "diverged" | "unknown";

export interface FleetStats {
  total: number;
  cloned: number;
  healthy: number;
  dirty: number;
  behind: number;
  syncing: number;
}

// Get all repos in fleet
export async function getFleetRepos(options?: {
  status?: RepoStatus;
  group?: string;
  owner?: string;
  limit?: number;
  offset?: number;
}): Promise<{ repos: FleetRepo[]; total: number }> {
  const correlationId = getCorrelationId();
  const startTime = Date.now();

  let query = db.select().from(fleetRepos);

  if (options?.status) {
    query = query.where(eq(fleetRepos.status, options.status));
  }
  if (options?.group) {
    query = query.where(eq(fleetRepos.ruGroup, options.group));
  }
  if (options?.owner) {
    query = query.where(eq(fleetRepos.owner, options.owner));
  }

  const total = await db.select({ count: count() }).from(fleetRepos);
  const repos = await query
    .orderBy(fleetRepos.fullName)
    .limit(options?.limit || 100)
    .offset(options?.offset || 0);

  logger.info({
    correlationId,
    duration_ms: Date.now() - startTime,
    repoCount: repos.length,
    total: total[0]?.count,
  }, "Fetched fleet repos");

  return { repos, total: total[0]?.count || 0 };
}

// Get fleet statistics
export async function getFleetStats(): Promise<FleetStats> {
  const [stats] = await db
    .select({
      total: count(),
      cloned: sql<number>`SUM(CASE WHEN ${fleetRepos.isCloned} THEN 1 ELSE 0 END)`,
      healthy: sql<number>`SUM(CASE WHEN ${fleetRepos.status} = 'healthy' THEN 1 ELSE 0 END)`,
      dirty: sql<number>`SUM(CASE WHEN ${fleetRepos.status} = 'dirty' THEN 1 ELSE 0 END)`,
      behind: sql<number>`SUM(CASE WHEN ${fleetRepos.status} = 'behind' THEN 1 ELSE 0 END)`,
    })
    .from(fleetRepos);

  // Count active sync operations
  const [syncing] = await db
    .select({ count: count() })
    .from(fleetSyncOps)
    .where(eq(fleetSyncOps.status, "running"));

  return {
    total: stats?.total || 0,
    cloned: stats?.cloned || 0,
    healthy: stats?.healthy || 0,
    dirty: stats?.dirty || 0,
    behind: stats?.behind || 0,
    syncing: syncing?.count || 0,
  };
}

// Add repo to fleet
export async function addRepoToFleet(params: {
  owner: string;
  name: string;
  url: string;
  sshUrl?: string;
  group?: string;
}): Promise<FleetRepo> {
  const correlationId = getCorrelationId();

  const repo = {
    id: generateId("repo_"),
    owner: params.owner,
    name: params.name,
    fullName: `${params.owner}/${params.name}`,
    url: params.url,
    sshUrl: params.sshUrl,
    ruGroup: params.group,
    status: "unknown" as RepoStatus,
    isCloned: false,
  };

  await db.insert(fleetRepos).values(repo);

  getHub().publish(
    { kind: "fleet", scope: "repos" },
    { type: "ru.repo_added", data: repo, timestamp: new Date().toISOString() }
  );

  logger.info({ correlationId, repoId: repo.id, fullName: repo.fullName }, "Added repo to fleet");

  return repo;
}

// Remove repo from fleet
export async function removeRepoFromFleet(repoId: string): Promise<void> {
  const repo = await db.select().from(fleetRepos).where(eq(fleetRepos.id, repoId)).get();

  if (!repo) {
    throw new NotFoundError(`Repo not found: ${repoId}`);
  }

  await db.delete(fleetRepos).where(eq(fleetRepos.id, repoId));

  getHub().publish(
    { kind: "fleet", scope: "repos" },
    { type: "ru.repo_removed", data: { repoId, fullName: repo.fullName }, timestamp: new Date().toISOString() }
  );

  logger.info({ repoId, fullName: repo.fullName }, "Removed repo from fleet");
}

// Update repo status
export async function updateRepoStatus(
  repoId: string,
  status: Partial<FleetRepo>
): Promise<void> {
  await db.update(fleetRepos)
    .set({
      ...status,
      updatedAt: sql`(unixepoch())`,
    })
    .where(eq(fleetRepos.id, repoId));

  getHub().publish(
    { kind: "fleet", scope: "repos" },
    { type: "ru.repo_status_changed", data: { repoId, status }, timestamp: new Date().toISOString() }
  );
}
```

### 2. Sync Operations Service

```typescript
// apps/gateway/src/services/ru-sync.service.ts

import { spawn, Subprocess } from "bun";
import { db } from "../db";
import { fleetRepos, fleetSyncOps } from "../db/schema";
import { getHub } from "../ws/hub";
import { logger } from "./logger";

// Active sync processes
const activeSyncs = new Map<string, Subprocess>();

export interface SyncOptions {
  parallelism?: number;
  dryRun?: boolean;
  force?: boolean;
  filter?: {
    repos?: string[];
    group?: string;
    owner?: string;
  };
}

export interface SyncProgress {
  total: number;
  completed: number;
  failed: number;
  current?: string;
  operations: SyncOperation[];
}

// Start fleet sync
export async function startFleetSync(
  triggeredBy: string,
  options?: SyncOptions
): Promise<{ sessionId: string }> {
  const correlationId = getCorrelationId();
  const sessionId = generateId("sync_");
  const startTime = Date.now();

  logger.info({
    correlationId,
    sessionId,
    triggeredBy,
    options,
  }, "Starting fleet sync");

  // Get target repos
  let repos: FleetRepo[];
  if (options?.filter?.repos) {
    repos = await db.select().from(fleetRepos)
      .where(inArray(fleetRepos.id, options.filter.repos));
  } else if (options?.filter?.group) {
    repos = await db.select().from(fleetRepos)
      .where(eq(fleetRepos.ruGroup, options.filter.group));
  } else if (options?.filter?.owner) {
    repos = await db.select().from(fleetRepos)
      .where(eq(fleetRepos.owner, options.filter.owner));
  } else {
    repos = await db.select().from(fleetRepos);
  }

  // Create sync operation records
  const operations = repos.map(repo => ({
    id: generateId("syncop_"),
    repoId: repo.id,
    repoFullName: repo.fullName,
    operation: repo.isCloned ? "pull" : "clone",
    status: "pending",
    triggeredBy,
    correlationId: sessionId,
  }));

  await db.insert(fleetSyncOps).values(operations);

  // Publish start event
  getHub().publish(
    { kind: "fleet", scope: "sync" },
    {
      type: "ru.sync_started",
      data: { sessionId, repoCount: repos.length, triggeredBy },
      timestamp: new Date().toISOString(),
    }
  );

  // Start sync process
  runSyncProcess(sessionId, repos, options);

  return { sessionId };
}

// Run the actual sync process
async function runSyncProcess(
  sessionId: string,
  repos: FleetRepo[],
  options?: SyncOptions
): Promise<void> {
  const correlationId = getCorrelationId();
  const parallelism = options?.parallelism || 4;

  let completed = 0;
  let failed = 0;

  // Process repos in batches
  for (let i = 0; i < repos.length; i += parallelism) {
    const batch = repos.slice(i, i + parallelism);

    await Promise.all(batch.map(async (repo) => {
      const opId = `syncop_${repo.id}`;
      const startTime = Date.now();

      try {
        // Update status to running
        await db.update(fleetSyncOps)
          .set({ status: "running", startedAt: sql`(unixepoch())` })
          .where(and(
            eq(fleetSyncOps.repoId, repo.id),
            eq(fleetSyncOps.correlationId, sessionId)
          ));

        getHub().publish(
          { kind: "fleet", scope: "sync" },
          {
            type: "ru.sync_repo_started",
            data: { sessionId, repoId: repo.id, fullName: repo.fullName },
            timestamp: new Date().toISOString(),
          }
        );

        // Run RU sync command
        const operation = repo.isCloned ? "pull" : "clone";
        const args = ["ru", operation === "clone" ? "sync" : "sync", "--json", repo.fullName];
        if (options?.dryRun) args.push("--dry-run");

        const proc = spawn(args, { stdout: "pipe", stderr: "pipe" });
        activeSyncs.set(repo.id, proc);

        const stdout = await new Response(proc.stdout).text();
        const stderr = await new Response(proc.stderr).text();
        const exitCode = await proc.exited;

        activeSyncs.delete(repo.id);

        const duration = Date.now() - startTime;
        const result = exitCode === 0 ? JSON.parse(stdout) : null;

        if (exitCode === 0) {
          // Success
          await db.update(fleetSyncOps)
            .set({
              status: "success",
              completedAt: sql`(unixepoch())`,
              durationMs: duration,
              toCommit: result?.commit,
              commitCount: result?.commits,
              filesChanged: result?.files,
            })
            .where(and(
              eq(fleetSyncOps.repoId, repo.id),
              eq(fleetSyncOps.correlationId, sessionId)
            ));

          // Update repo status
          await updateRepoStatus(repo.id, {
            isCloned: true,
            status: "healthy",
            lastSyncAt: new Date(),
            lastCommit: result?.commit,
          });

          completed++;
        } else {
          // Failed
          await db.update(fleetSyncOps)
            .set({
              status: "failed",
              completedAt: sql`(unixepoch())`,
              durationMs: duration,
              error: stderr || "Unknown error",
            })
            .where(and(
              eq(fleetSyncOps.repoId, repo.id),
              eq(fleetSyncOps.correlationId, sessionId)
            ));

          failed++;
        }

        // Publish progress
        getHub().publish(
          { kind: "fleet", scope: "sync" },
          {
            type: "ru.sync_repo_completed",
            data: {
              sessionId,
              repoId: repo.id,
              fullName: repo.fullName,
              success: exitCode === 0,
              duration,
              completed,
              failed,
              total: repos.length,
            },
            timestamp: new Date().toISOString(),
          }
        );

        logger.info({
          correlationId,
          sessionId,
          repoId: repo.id,
          success: exitCode === 0,
          duration_ms: duration,
        }, "Sync operation completed");

      } catch (error) {
        failed++;
        logger.error({ correlationId, sessionId, repoId: repo.id, error }, "Sync operation failed");
      }
    }));
  }

  // Publish completion
  getHub().publish(
    { kind: "fleet", scope: "sync" },
    {
      type: "ru.sync_completed",
      data: { sessionId, completed, failed, total: repos.length },
      timestamp: new Date().toISOString(),
    }
  );

  logger.info({
    correlationId,
    sessionId,
    completed,
    failed,
    total: repos.length,
  }, "Fleet sync completed");
}

// Cancel sync
export async function cancelSync(sessionId: string): Promise<void> {
  // Cancel active processes
  for (const [repoId, proc] of activeSyncs) {
    proc.kill();
    activeSyncs.delete(repoId);
  }

  // Update pending operations to cancelled
  await db.update(fleetSyncOps)
    .set({ status: "cancelled" })
    .where(and(
      eq(fleetSyncOps.correlationId, sessionId),
      inArray(fleetSyncOps.status, ["pending", "running"])
    ));

  getHub().publish(
    { kind: "fleet", scope: "sync" },
    { type: "ru.sync_cancelled", data: { sessionId }, timestamp: new Date().toISOString() }
  );
}

// Get sync history
export async function getSyncHistory(options?: {
  repoId?: string;
  sessionId?: string;
  limit?: number;
}): Promise<SyncOperation[]> {
  let query = db.select().from(fleetSyncOps);

  if (options?.repoId) {
    query = query.where(eq(fleetSyncOps.repoId, options.repoId));
  }
  if (options?.sessionId) {
    query = query.where(eq(fleetSyncOps.correlationId, options.sessionId));
  }

  return await query
    .orderBy(desc(fleetSyncOps.createdAt))
    .limit(options?.limit || 50);
}
```

### 3. Agent Sweep Service

```typescript
// apps/gateway/src/services/ru-sweep.service.ts

import { spawn } from "bun";
import { db } from "../db";
import { agentSweepSessions, agentSweepPlans, agentSweepLogs, fleetRepos } from "../db/schema";
import { getHub } from "../ws/hub";
import { logger } from "./logger";
import { requestSLBApproval } from "./slb.service";

export interface SweepConfig {
  targetRepos: string[] | "*";
  parallelism?: number;
  dryRun?: boolean;
  autoApprove?: boolean;
  phase1Timeout?: number;  // Analysis timeout (default 300s)
  phase2Timeout?: number;  // Planning timeout (default 600s)
  phase3Timeout?: number;  // Execution timeout (default 300s)
}

// Start agent sweep session
export async function startAgentSweep(
  triggeredBy: string,
  config: SweepConfig
): Promise<AgentSweepSession> {
  const correlationId = getCorrelationId();
  const sessionId = generateId("sweep_");

  logger.info({ correlationId, sessionId, triggeredBy, config }, "Starting agent sweep");

  // Determine target repos
  let repos: FleetRepo[];
  if (config.targetRepos === "*") {
    repos = await db.select().from(fleetRepos).where(eq(fleetRepos.isCloned, true));
  } else {
    repos = await db.select().from(fleetRepos)
      .where(inArray(fleetRepos.id, config.targetRepos));
  }

  // Create session
  const session = {
    id: sessionId,
    targetRepos: JSON.stringify(repos.map(r => r.id)),
    repoCount: repos.length,
    config: JSON.stringify(config),
    parallelism: config.parallelism || 1,
    status: "pending",
    slbApprovalRequired: !config.autoApprove,
    triggeredBy,
  };

  await db.insert(agentSweepSessions).values(session);

  // Log session start
  await logSweepEvent(sessionId, "info", "Agent sweep session created", { repoCount: repos.length });

  // Publish event
  getHub().publish(
    { kind: "fleet", scope: "sweep" },
    {
      type: "ru.sweep_created",
      data: { sessionId, repoCount: repos.length, triggeredBy },
      timestamp: new Date().toISOString(),
    }
  );

  // If auto-approve, start immediately; otherwise wait for SLB approval
  if (config.autoApprove) {
    runSweepPhases(sessionId, repos, config);
  } else {
    // Request SLB approval
    const approval = await requestSLBApproval({
      type: "agent-sweep",
      sessionId,
      description: `Agent sweep for ${repos.length} repositories`,
      metadata: { repos: repos.map(r => r.fullName) },
    });

    await db.update(agentSweepSessions)
      .set({ slbApprovalId: approval.id })
      .where(eq(agentSweepSessions.id, sessionId));
  }

  return await db.select().from(agentSweepSessions).where(eq(agentSweepSessions.id, sessionId)).get();
}

// Run all three phases
async function runSweepPhases(
  sessionId: string,
  repos: FleetRepo[],
  config: SweepConfig
): Promise<void> {
  const correlationId = getCorrelationId();

  try {
    // Update to running
    await db.update(agentSweepSessions)
      .set({ status: "running", startedAt: sql`(unixepoch())`, currentPhase: "phase1_analysis" })
      .where(eq(agentSweepSessions.id, sessionId));

    getHub().publish(
      { kind: "fleet", scope: "sweep" },
      { type: "ru.sweep_started", data: { sessionId }, timestamp: new Date().toISOString() }
    );

    // Phase 1: Analysis
    await runPhase1Analysis(sessionId, repos, config);

    // Phase 2: Planning
    await runPhase2Planning(sessionId, repos, config);

    // Phase 3: Execution (if not dry run)
    if (!config.dryRun) {
      await runPhase3Execution(sessionId, config);
    }

    // Complete
    await db.update(agentSweepSessions)
      .set({
        status: "completed",
        completedAt: sql`(unixepoch())`,
        totalDurationMs: sql`((unixepoch()) - ${agentSweepSessions.startedAt}) * 1000`,
      })
      .where(eq(agentSweepSessions.id, sessionId));

    getHub().publish(
      { kind: "fleet", scope: "sweep" },
      { type: "ru.sweep_completed", data: { sessionId }, timestamp: new Date().toISOString() }
    );

  } catch (error) {
    await db.update(agentSweepSessions)
      .set({ status: "failed" })
      .where(eq(agentSweepSessions.id, sessionId));

    await logSweepEvent(sessionId, "error", "Sweep failed", { error: error.message });

    getHub().publish(
      { kind: "fleet", scope: "sweep" },
      { type: "ru.sweep_failed", data: { sessionId, error: error.message }, timestamp: new Date().toISOString() }
    );

    logger.error({ correlationId, sessionId, error }, "Agent sweep failed");
  }
}

// Phase 1: Analysis
async function runPhase1Analysis(
  sessionId: string,
  repos: FleetRepo[],
  config: SweepConfig
): Promise<void> {
  await logSweepEvent(sessionId, "info", "Starting Phase 1: Analysis");

  let analyzed = 0;
  const timeout = config.phase1Timeout || 300;

  for (const repo of repos) {
    const startTime = Date.now();

    // Run ru agent-sweep --phase1
    const proc = spawn(
      ["ru", "agent-sweep", "--phase", "1", "--json", "--timeout", String(timeout), repo.fullName],
      { stdout: "pipe", stderr: "pipe" }
    );

    const stdout = await new Response(proc.stdout).text();
    const exitCode = await proc.exited;

    if (exitCode === 0) {
      const result = JSON.parse(stdout);
      await logSweepEvent(sessionId, "info", `Analyzed ${repo.fullName}`, {
        duration_ms: Date.now() - startTime,
        findings: result.findings,
      });
      analyzed++;
    } else {
      await logSweepEvent(sessionId, "warn", `Analysis failed for ${repo.fullName}`);
    }

    // Update progress
    await db.update(agentSweepSessions)
      .set({ reposAnalyzed: analyzed })
      .where(eq(agentSweepSessions.id, sessionId));

    getHub().publish(
      { kind: "fleet", scope: "sweep" },
      {
        type: "ru.sweep_progress",
        data: { sessionId, phase: "phase1", analyzed, total: repos.length },
        timestamp: new Date().toISOString(),
      }
    );
  }

  await db.update(agentSweepSessions)
    .set({
      currentPhase: "phase2_planning",
      phase1CompletedAt: sql`(unixepoch())`,
    })
    .where(eq(agentSweepSessions.id, sessionId));

  await logSweepEvent(sessionId, "info", "Phase 1 completed", { analyzed });
}

// Phase 2: Planning
async function runPhase2Planning(
  sessionId: string,
  repos: FleetRepo[],
  config: SweepConfig
): Promise<void> {
  await logSweepEvent(sessionId, "info", "Starting Phase 2: Planning");

  let planned = 0;
  const timeout = config.phase2Timeout || 600;

  for (const repo of repos) {
    // Run ru agent-sweep --phase2
    const proc = spawn(
      ["ru", "agent-sweep", "--phase", "2", "--json", "--timeout", String(timeout), repo.fullName],
      { stdout: "pipe", stderr: "pipe" }
    );

    const stdout = await new Response(proc.stdout).text();
    const exitCode = await proc.exited;

    if (exitCode === 0) {
      const plan = JSON.parse(stdout);

      // Store plan
      const planRecord = {
        id: generateId("plan_"),
        sessionId,
        repoId: repo.id,
        repoFullName: repo.fullName,
        planJson: JSON.stringify(plan),
        actionCount: plan.actions?.length || 0,
        riskLevel: assessRiskLevel(plan),
        commitActions: plan.actions?.filter(a => a.type === "commit").length || 0,
        releaseActions: plan.actions?.filter(a => a.type === "release").length || 0,
        branchActions: plan.actions?.filter(a => a.type === "branch").length || 0,
        prActions: plan.actions?.filter(a => a.type === "pr").length || 0,
        approvalStatus: "pending",
      };

      await db.insert(agentSweepPlans).values(planRecord);
      planned++;

      await logSweepEvent(sessionId, "info", `Created plan for ${repo.fullName}`, {
        planId: planRecord.id,
        actionCount: planRecord.actionCount,
        riskLevel: planRecord.riskLevel,
      });
    }

    // Update progress
    await db.update(agentSweepSessions)
      .set({ reposPlanned: planned })
      .where(eq(agentSweepSessions.id, sessionId));

    getHub().publish(
      { kind: "fleet", scope: "sweep" },
      {
        type: "ru.sweep_progress",
        data: { sessionId, phase: "phase2", planned, total: repos.length },
        timestamp: new Date().toISOString(),
      }
    );
  }

  await db.update(agentSweepSessions)
    .set({
      currentPhase: "phase3_execution",
      phase2CompletedAt: sql`(unixepoch())`,
    })
    .where(eq(agentSweepSessions.id, sessionId));

  await logSweepEvent(sessionId, "info", "Phase 2 completed", { planned });
}

// Phase 3: Execution
async function runPhase3Execution(
  sessionId: string,
  config: SweepConfig
): Promise<void> {
  await logSweepEvent(sessionId, "info", "Starting Phase 3: Execution");

  // Get approved plans
  const plans = await db.select()
    .from(agentSweepPlans)
    .where(and(
      eq(agentSweepPlans.sessionId, sessionId),
      eq(agentSweepPlans.approvalStatus, "approved")
    ));

  let executed = 0;
  let failed = 0;
  const timeout = config.phase3Timeout || 300;

  for (const plan of plans) {
    const startTime = Date.now();

    // Update plan status
    await db.update(agentSweepPlans)
      .set({ executionStatus: "running" })
      .where(eq(agentSweepPlans.id, plan.id));

    // Run ru agent-sweep --phase3
    const proc = spawn(
      ["ru", "agent-sweep", "--phase", "3", "--json", "--timeout", String(timeout), "--plan", plan.planJson],
      { stdout: "pipe", stderr: "pipe" }
    );

    const stdout = await new Response(proc.stdout).text();
    const exitCode = await proc.exited;

    const result = exitCode === 0 ? JSON.parse(stdout) : { error: stdout };

    await db.update(agentSweepPlans)
      .set({
        executionStatus: exitCode === 0 ? "completed" : "failed",
        executedAt: sql`(unixepoch())`,
        executionResult: JSON.stringify(result),
      })
      .where(eq(agentSweepPlans.id, plan.id));

    if (exitCode === 0) {
      executed++;
    } else {
      failed++;
    }

    await logSweepEvent(sessionId, exitCode === 0 ? "info" : "error",
      `Executed plan for ${plan.repoFullName}`, {
        planId: plan.id,
        success: exitCode === 0,
        duration_ms: Date.now() - startTime,
      });

    // Update session progress
    await db.update(agentSweepSessions)
      .set({ reposExecuted: executed, reposFailed: failed })
      .where(eq(agentSweepSessions.id, sessionId));

    getHub().publish(
      { kind: "fleet", scope: "sweep" },
      {
        type: "ru.sweep_progress",
        data: { sessionId, phase: "phase3", executed, failed, total: plans.length },
        timestamp: new Date().toISOString(),
      }
    );
  }

  await db.update(agentSweepSessions)
    .set({ phase3CompletedAt: sql`(unixepoch())` })
    .where(eq(agentSweepSessions.id, sessionId));

  await logSweepEvent(sessionId, "info", "Phase 3 completed", { executed, failed });
}

// Helper: Log sweep event
async function logSweepEvent(
  sessionId: string,
  level: string,
  message: string,
  data?: Record<string, unknown>
): Promise<void> {
  await db.insert(agentSweepLogs).values({
    id: generateId("log_"),
    sessionId,
    phase: "sweep",
    level,
    message,
    data: data ? JSON.stringify(data) : null,
  });

  logger.info({ sessionId, level, message, data }, "Sweep event");
}

// Helper: Assess risk level
function assessRiskLevel(plan: unknown): "low" | "medium" | "high" | "critical" {
  const actions = (plan as any).actions || [];
  const hasRelease = actions.some(a => a.type === "release");
  const hasDestructive = actions.some(a => a.destructive);
  const actionCount = actions.length;

  if (hasDestructive) return "critical";
  if (hasRelease && actionCount > 5) return "high";
  if (hasRelease || actionCount > 10) return "medium";
  return "low";
}

// Approve plan
export async function approveSweepPlan(
  planId: string,
  approvedBy: string
): Promise<void> {
  await db.update(agentSweepPlans)
    .set({
      approvalStatus: "approved",
      approvedBy,
      approvedAt: sql`(unixepoch())`,
    })
    .where(eq(agentSweepPlans.id, planId));

  logger.info({ planId, approvedBy }, "Sweep plan approved");
}

// Reject plan
export async function rejectSweepPlan(
  planId: string,
  rejectedBy: string,
  reason: string
): Promise<void> {
  await db.update(agentSweepPlans)
    .set({
      approvalStatus: "rejected",
      rejectedReason: reason,
    })
    .where(eq(agentSweepPlans.id, planId));

  logger.info({ planId, rejectedBy, reason }, "Sweep plan rejected");
}

// Get session with plans
export async function getSweepSession(sessionId: string): Promise<SweepSessionWithPlans> {
  const session = await db.select()
    .from(agentSweepSessions)
    .where(eq(agentSweepSessions.id, sessionId))
    .get();

  if (!session) {
    throw new NotFoundError(`Sweep session not found: ${sessionId}`);
  }

  const plans = await db.select()
    .from(agentSweepPlans)
    .where(eq(agentSweepPlans.sessionId, sessionId));

  const logs = await db.select()
    .from(agentSweepLogs)
    .where(eq(agentSweepLogs.sessionId, sessionId))
    .orderBy(desc(agentSweepLogs.timestamp))
    .limit(100);

  return { ...session, plans, logs };
}
