### 1. Pagination Types
```typescript
// packages/shared/src/api/pagination.ts

/**
 * Pagination request parameters.
 */
export interface PaginationParams {
  /** Maximum items to return (default 50, max 100) */
  limit?: number;
  /** Cursor for forward pagination (exclusive) */
  startingAfter?: string;
  /** Cursor for backward pagination (exclusive) */
  endingBefore?: string;
}

/**
 * Pagination response metadata.
 */
export interface PaginationMeta {
  /** Whether more items exist */
  hasMore: boolean;
  /** Cursor for next page (if hasMore) */
  nextCursor?: string;
  /** Cursor for previous page (if applicable) */
  prevCursor?: string;
  /** Total count (optional, may be expensive) */
  total?: number;
}

/**
 * Validated/normalized pagination params.
 */
export interface NormalizedPaginationParams {
  limit: number;
  cursor?: string;
  direction: "forward" | "backward";
}
```

### 2. Cursor Encoding
```typescript
/**
 * Cursor payload structure.
 * Cursors are opaque to clients but encode:
 * - Resource ID for keyset pagination
 * - Sort field value (for stable ordering)
 * - Timestamp for cursor expiration
 */
interface CursorPayload {
  id: string;
  sortValue?: string | number;
  createdAt: number;
}

/**
 * Encode a cursor from payload.
 */
export function encodeCursor(payload: CursorPayload): string {
  const json = JSON.stringify(payload);
  return Buffer.from(json).toString("base64url");
}

/**
 * Decode a cursor to payload.
 * Returns undefined if invalid or expired.
 */
export function decodeCursor(cursor: string): CursorPayload | undefined {
  try {
    const json = Buffer.from(cursor, "base64url").toString();
    const payload = JSON.parse(json) as CursorPayload;

    // Validate structure
    if (!payload.id || !payload.createdAt) return undefined;

    // Check expiration (24 hours)
    const age = Date.now() - payload.createdAt;
    if (age > 24 * 60 * 60 * 1000) return undefined;

    return payload;
  } catch {
    return undefined;
  }
}
```

### 3. Pagination Utility
```typescript
/**
 * Normalize and validate pagination params from request.
 */
export function normalizePaginationParams(
  params: PaginationParams,
  defaults: { limit: number; maxLimit: number } = { limit: 50, maxLimit: 100 }
): NormalizedPaginationParams {
  const limit = Math.min(
    Math.max(1, params.limit ?? defaults.limit),
    defaults.maxLimit
  );

  if (params.endingBefore) {
    return {
      limit,
      cursor: params.endingBefore,
      direction: "backward",
    };
  }

  return {
    limit,
    cursor: params.startingAfter,
    direction: "forward",
  };
}
```

